proof_block:
// Step 1: equate the two abstractified un_acked sequences via their
// common truncate_un_ack_list(...) target from the two ensures conjuncts.
// This forces z3 to instantiate the abstractify_cmessage_seq term on
// both post states with the same RHS, so the per-run quantifiers from
// the ensures clauses line up.
let trunc = truncate_un_ack_list(
    abstractify_cmessage_seq(pre_self_.un_acked@),
    seqno_acked as nat,
);
assert(abstractify_cmessage_seq(post1_self_.un_acked@) == trunc);
assert(abstractify_cmessage_seq(post2_self_.un_acked@) == trunc);
assert(abstractify_cmessage_seq(post1_self_.un_acked@)
       == abstractify_cmessage_seq(post2_self_.un_acked@));

// Step 2: extract the `un_acked_list_valid_for_dst` invariant for both
// post states from `valid_list` (which is unfolded by `valid(dst)`).
assert(post1_self_.valid(dst));
assert(post2_self_.valid(dst));
assert(CAckState::valid_list(post1_self_.un_acked@,
    post1_self_.num_packets_acked as int, dst));
assert(CAckState::valid_list(post2_self_.un_acked@,
    post2_self_.num_packets_acked as int, dst));
assert(CAckState::un_acked_list_valid_for_dst(post1_self_.un_acked@, dst));
assert(CAckState::un_acked_list_valid_for_dst(post2_self_.un_acked@, dst));

// Step 3: functional-uniqueness lemma closes Seq ext-equality.
lemma_truncate_un_acked_unique(
    post1_self_.un_acked@, post2_self_.un_acked@, dst,
);
assert(post1_self_.un_acked@ =~= post2_self_.un_acked@);

// Lift Seq =~= to Vec =~= (Vec is ext-equal by view).
assert(post1_self_.un_acked =~= post2_self_.un_acked);

// Step 4: num_packets_acked is pinned to seqno_acked by both ensures.
assert(post1_self_.num_packets_acked == seqno_acked);
assert(post2_self_.num_packets_acked == seqno_acked);
assert(post1_self_.num_packets_acked == post2_self_.num_packets_acked);

// Step 5: r1, r2 are both `()`, and CAckState has #[verifier::ext_equal],
// so field-wise =~= on (num_packets_acked, un_acked) lifts to
// post1_self_ =~= post2_self_.
assert(r1 == r2);
assert(post1_self_ =~= post2_self_);

helper_lemmas:
// Functional-uniqueness for `un_acked` lists: under the
// `un_acked_list_valid_for_dst` invariant (which forces every element
// to be a `Message{..}` variant with `dst@ == dst`), two lists with
// equal `abstractify_cmessage_seq` views must coincide structurally.
//
// Proof strategy:
//  * map_values preserves length, so the two lists have equal length.
//  * For each index, map_values picks out the per-element view, so
//    same map_values output ⇒ pointwise `msgs1[i]@ == msgs2[i]@`.
//  * Both elements are the `Message` variant (from un_acked_valid), so
//    `==`-on-CSingleMessage decomposes to `seqno`, `dst`, `m` equality.
//    Pointwise view equality on the lifted `SingleMessage::Message{..}`
//    pins each component, and the CSingleMessage enum's structural `==`
//    closes the case under `=~~=` (deep ext-equal).
proof fn lemma_truncate_un_acked_unique(
    msgs1: Seq<CSingleMessage>,
    msgs2: Seq<CSingleMessage>,
    dst: AbstractEndPoint,
)
    requires
        CAckState::un_acked_list_valid_for_dst(msgs1, dst),
        CAckState::un_acked_list_valid_for_dst(msgs2, dst),
        abstractify_cmessage_seq(msgs1) == abstractify_cmessage_seq(msgs2),
    ensures
        msgs1 =~= msgs2,
{
    let a1 = abstractify_cmessage_seq(msgs1);
    let a2 = abstractify_cmessage_seq(msgs2);
    // map_values preserves length.
    assert(a1.len() == msgs1.len());
    assert(a2.len() == msgs2.len());
    assert(a1 == a2);
    assert(msgs1.len() == msgs2.len());

    // Pointwise element equality. The two ingredients are:
    //   * `a1[i] == msgs1[i]@`   (definition of map_values)
    //   * each msgs1[i] / msgs2[i] is the `Message{..}` variant,
    //     so the lifted view pins (seqno as nat, dst@, m@) and
    //     CSingleMessage::== decomposes accordingly.
    assert forall|i: int| 0 <= i < msgs1.len() implies msgs1[i] == msgs2[i] by {
        // map_values unfolds to a pointwise application.
        assert(a1[i] == msgs1[i]@);
        assert(a2[i] == msgs2[i]@);
        assert(msgs1[i]@ == msgs2[i]@);

        // Both elements are the Message variant under the validity
        // invariant; pin that so the enum-equality case-split has only
        // one arm.
        assert(CAckState::un_acked_valid(&msgs1[i]));
        assert(CAckState::un_acked_valid(&msgs2[i]));
        assert(msgs1[i] is Message);
        assert(msgs2[i] is Message);

        // Deep ext-equal cascade through the SingleMessage::Message
        // view: seqno/dst/m views match, and the inner types have
        // ext-equal lifted from view-equal. `=~~=` triggers Verus's
        // recursive structural-equality unfolding on both sides.
        assert(msgs1[i] =~~= msgs2[i]);
    };
}
